#include<bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<ll, ll>PII
using namespace std;
CI MAXN=2e4+5;
int maxn=0,ms=0,me=0,i,j=0,k,l,num=0,fu=0,w[MAXN];
char c,t[MAXN],s[MAXN];
bool check(char b[],int begin,int end)//判断回文 
{
    for(int i=0;i<end-begin;++i)
    {
        if(b[begin+i]==b[end-i]||b[begin+i]+32==b[end-i]||b[begin+i]==b[end-i]+32)
		{
            continue;
        }
		else
		{
            return false;
        }
    }
    return true;
}
int main(void){
    while(c=getchar())
    {
        if(c==EOF)
		{
            break;
        }
        s[++num]=c;
    }
    for(i=1;i<=num;++i)
	{
        if(s[i]>='a'&&s[i]<='z'||s[i]>='A'&&s[i]<='Z')
		{
            t[fu]=s[i];
            w[fu++]=i;
        }
    }
    for(i=0;i<fu;++i)
	{
        int temp=0;
        for(j=i+maxn+1;j<min(i+2001,fu);++j)
		{
            if(check(t,i,j))
			{
                temp=j-i+1;
            }
        }
        if(temp>maxn)
		{
            maxn=temp;
            ms=w[i];
            me=w[i+temp-1];
        }
    }
    printf("%d\n",maxn);
    for(i=ms;i<=me;++i)
	{
        printf("%c",s[i]);
    }
    return false;
}
